import React, { useState } from "react";
import styled from "styled-components";
import ProductList from "./components/Product/ProductList";
import RawMaterialList from "./components/RawMaterial/RawMaterialList";

const Layout = styled.div`
  display: flex;
  min-height: 100vh;
  font-family: "Segoe UI", sans-serif;
  background-color: #f4f6f9;
`;

const Sidebar = styled.div`
  width: 240px;
  background: #1e293b;
  color: white;
  padding: 20px;
`;

const SidebarTitle = styled.h2`
  font-size: 18px;
  margin-bottom: 30px;
`;

const MenuItem = styled.div`
  padding: 12px;
  margin-bottom: 10px;
  border-radius: 8px;
  cursor: pointer;
  background: ${(props) => (props.active ? "#334155" : "transparent")};

  &:hover {
    background: #334155;
  }
`;

const Content = styled.div`
  flex: 1;
  padding: 30px;
`;

const Header = styled.div`
  margin-bottom: 30px;
`;

const Title = styled.h1`
  font-size: 26px;
  color: #1e293b;
`;

function App() {
  const [activePage, setActivePage] = useState("products");

  const renderPage = () => {
    switch (activePage) {
      case "products":
        return <ProductList />;
      case "materials":
        return <RawMaterialList />;
      case "production":
        return <ProductProductionList />;
      default:
        return <ProductList />;
    }
  };

  return (
    <Layout>
      <Sidebar>
        <SidebarTitle>Inventory System</SidebarTitle>

        <MenuItem
          active={activePage === "products"}
          onClick={() => setActivePage("products")}
        >
          Products
        </MenuItem>

        <MenuItem
          active={activePage === "materials"}
          onClick={() => setActivePage("materials")}
        >
          Raw Materials
        </MenuItem>

        <MenuItem
          active={activePage === "production"}
          onClick={() => setActivePage("production")}
        >
          Production
        </MenuItem>
      </Sidebar>

      <Content>
        <Header>
          <Title>
            {activePage === "products" && "Products"}
            {activePage === "materials" && "Raw Materials"}
            {activePage === "production" && "Production Suggestions"}
          </Title>
        </Header>

        {renderPage()}
      </Content>
    </Layout>
  );
}

export default App;
